DELETE FROM tblKeySets WHERE fldSetID IN (1101,1102,1103,1104,1105,1106,1107,1108,1109,1110,9997,9998,9999)
DELETE FROM tblKeySetsKeys WHERE fldSetID IN (1101,1102,1103,1104,1105,1106,1107,1108,1109,1110,9997,9998,9999)



IF NOT EXISTS (SELECT 1 FROM tblConfigValues WHERE fldGUID=1575) BEGIN INSERT INTO tblConfigValues SELECT fldID,1575,9997,1,fldStore FROM tblTerminals WHERE fldType=1 AND fldStore=(SELECT fldID FROM tblStores WHERE fldLocal=1) END

UPDATE tblReplicationTables SET fldClearRequest=1 WHERE fldTableName LIKE 'tblKeySets%' OR fldTableName LIKE 'tblConfigValues'
